def gen(rng, size):
    from collections import deque
    n = max(1, min(size, 300))
    vals = [rng.randint(1, 100) for _ in range(n)]
    class N:
        def __init__(self, val):
            self.val = val
            self.left = None
            self.right = None
    root = N(vals[0])
    nodes = [root]
    for v in vals[1:]:
        for _ in range(20):
            parent = rng.choice(nodes)
            if parent.left is None or parent.right is None:
                break
        if parent.left is None and (parent.right is not None or rng.random() < 0.5):
            parent.left = N(v)
            nodes.append(parent.left)
        elif parent.right is None:
            parent.right = N(v)
            nodes.append(parent.right)
    result = [root.val]
    q = deque([root])
    while q:
        node = q.popleft()
        for child in (node.left, node.right):
            if child is not None:
                result.append(child.val)
                q.append(child)
            else:
                result.append(None)
    while result and result[-1] is None:
        result.pop()
    distance = rng.randint(1, 10)
    return [result, distance]

