class Solution:
    def countPairs(self, root, distance):
        from collections import deque, defaultdict
        adj = defaultdict(list)
        leaves = []
        def dfs(node, parent):
            if not node:
                return
            if parent is not None:
                adj[id(node)].append(id(parent))
                adj[id(parent)].append(id(node))
            if not node.left and not node.right:
                leaves.append(id(node))
            dfs(node.left, node)
            dfs(node.right, node)
        dfs(root, None)
        count = 0
        for i in range(len(leaves)):
            dist = {leaves[i]: 0}
            q = deque([leaves[i]])
            while q:
                u = q.popleft()
                for v in adj[u]:
                    if v not in dist:
                        dist[v] = dist[u] + 1
                        q.append(v)
            for j in range(i + 1, len(leaves)):
                if dist.get(leaves[j], float('inf')) <= distance:
                    count += 1
        return count

